const chatForm = document.getElementById('chat-form');
const userInput = document.getElementById('user-input');
const sendBtn = document.getElementById('send-btn');
const chatBox = document.getElementById('chat-box');
const themeBtn = document.getElementById('theme-btn');
const themeIcon = document.getElementById('theme-icon');
const welcomeScreen = document.getElementById('welcome-screen');
const sunIcon = `
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="theme-icon-svg" id="theme-icon">
        <circle cx="12" cy="12" r="4"></circle>
        <path d="M12 2v2"></path><path d="M12 20v2"></path>
        <path d="m4.93 4.93 1.41 1.41"></path><path d="m17.66 17.66 1.41 1.41"></path>
        <path d="M2 12h2"></path><path d="M20 12h2"></path>
        <path d="m6.34 17.66-1.41 1.41"></path><path d="m19.07 4.93-1.41 1.41"></path>
    </svg>`;
const moonIcon = `
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="theme-icon-svg" id="theme-icon">
        <path d="M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z"></path>
    </svg>`;

marked.use({
    breaks: true,
    gfm: true,
    renderer: {
        link(href, title, text) {
            const linkTitle = title ? ` title="${title}"` : '';
            return `<a target="_blank" rel="noopener noreferrer" href="${href}"${linkTitle}>${text}</a>`;
        }
    }
});

let currentTheme = localStorage.getItem('theme') || 'light';
document.documentElement.setAttribute('data-theme', currentTheme);
updateThemeUI();

themeBtn.addEventListener('click', () => {
    currentTheme = currentTheme === 'light' ? 'dark' : 'light';
    document.documentElement.setAttribute('data-theme', currentTheme);
    localStorage.setItem('theme', currentTheme);
    updateThemeUI();
});

function updateThemeUI() {
    themeIcon.innerHTML = (currentTheme === 'dark') ? sunIcon : moonIcon;
}

userInput.addEventListener('input', function() {
    this.style.height = 'auto';
    this.style.height = (this.scrollHeight) + 'px';
});

userInput.addEventListener('keydown', function(e) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        sendMessage();
    }
});

sendBtn.addEventListener('click', sendMessage);


function createMessageElement(text, sender, isMarkdown = false, responseTime = null) {
    const row = document.createElement('div');
    
    if (sender === 'user') {
        row.className = 'user-row';
        const safeText = escapeHTML(text);
        row.innerHTML = `<div class="user-bubble" dir="auto">${safeText}</div>`;
    } else {
        row.className = 'bot-row';
        
        let contentHTML = '';
        if (isMarkdown) {
            let processedText = text.replace(/([0-9۰-۹]+-[0-9۰-۹]+)/g, '<span dir="ltr" style="display: inline-block;">$1</span>');
            contentHTML = marked.parse(processedText);
        } else {
            let safeText = escapeHTML(text);
            safeText = safeText.replace(/([0-9۰-۹]+-[0-9۰-۹]+)/g, '<span dir="ltr" style="display: inline-block;">$1</span>');
            contentHTML = `<p>${safeText}</p>`;
        }

        // اگر زمان پاسخگویی وجود داشت، یک المان کوچک برای نمایش آن می‌سازیم
        let timeHTML = '';
        if (responseTime !== null) {
            timeHTML = `<div style="font-size: 0.75rem; color: gray; margin-top: 8px; text-align: left;" dir="rtl">⏱ زمان پاسخگویی: ${responseTime} ثانیه</div>`;
        }

        row.innerHTML = `
            <div class="bot-content">
                <div class="text-content" dir="auto">
                    ${contentHTML}
                    ${timeHTML}
                </div>
            </div>
        `;
    }
    return row;
}



function escapeHTML(str) {
    return str.replace(/[&<>'"]/g, tag => ({
        '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;'
    }[tag]));
}

