function scrollToBottom() {
    chatBox.scrollTop = chatBox.scrollHeight;
}

async function sendMessage() {
    if (sendBtn.disabled) return;
    
    const text = userInput.value.trim();
    if (!text) return;

    if (welcomeScreen) welcomeScreen.style.display = 'none';

    chatBox.appendChild(createMessageElement(text, 'user', false));
    
    userInput.value = '';
    userInput.style.height = 'auto';
    sendBtn.disabled = true;
    scrollToBottom();

    const loadingEl = showTypingIndicator();

    try {
        const response = await fetch('/chat', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ question: text })
        });

        if (!response.ok) throw new Error('Server error');
        const data = await response.json();

        if (loadingEl) loadingEl.remove();
        
        // پارامتر زمان را به تابع پاس می‌دهیم ---> data.response_time
        chatBox.appendChild(createMessageElement(data.answer, 'bot', data.is_markdown, data.response_time));
        
    } catch (error) {
        console.error('Error:', error);
        if (loadingEl) loadingEl.remove();
        chatBox.appendChild(createMessageElement('⚠️ خطا در ارتباط با سرور', 'bot', false));
    } finally {
        sendBtn.disabled = false;
        scrollToBottom();
    }
}

chatForm.addEventListener('submit', function(event) {
    event.preventDefault();
    sendMessage(); 
});
